sql:
SELECT COUNT(*) 
FROM general_education 
WHERE designation_name = 'Humanities, Fine Arts & Design';

SELECT COUNT(class_id) AS class_count
FROM class_schedules
WHERE enrollment_limit > current_enrollment;

SELECT DISTINCT course_title
FROM courses
ORDER BY course_title ASC;

SELECT COUNT(course_id) AS course_count
FROM course_categories
WHERE category_name = 'Education';

external_knowledge:
- Average rating is a measure of the overall satisfaction of students with the course;
- Popularity is determined by the number of students enrolled in the course;
- Courses with higher average ratings and more enrolled students are considered more successful.

sql:
SELECT COUNT(DISTINCT c.course_id) AS unique_courses_with_gen_ed 
FROM courses c
JOIN general_education ge ON c.course_id = ge.course_id;

external_knowledge:
